const tableInfo = reactive({
  columns: [
    {
      name: 'id',
      label: 'ID',
      width: 180,
    },
    {
      name: 'product',
      label: '\u5546\u54C1\u540D\u7A31',
      sort: false,
      width: 180,
    },
    {
      name: 'price',
      label: '\u50F9\u683C',
      width: 180,
      sort: true,
    },
    {
      name: 'storage',
      label: '\u5EAB\u5B58',
      sort: true,
    },
    {
      name: 'tags',
      width: 220,
      label: '\u6A19\u7C64',
    },
    {
      name: 'btns',
      width: 200,
      label: '',
    },
  ],
  data: [
    { product: 'aaa', price: 200, storage: 25, id: uuidv4() },
    ...
    { product: 'bbbb', price: 100, storage: 15, id: uuidv4() },
  ],
    isLoading: false,
});

// \u76EE\u524D\u662F\u4F7F\u7528"name" \u8A3B\u518A\u4E00\u500B\u5168\u57DF\u7684table\u7269\u4EF6
